import React, { useState } from 'react';
import { Outlet, Link, Navigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const StaffLayout = () => {
  const { user, logout } = useAuth();
  const { staffList, updatePassword } = useData();
  const [showModal, setShowModal] = useState(false);
  const [passForm, setPassForm] = useState({ oldPass: '', newPass: '', confirmPass: '' });

  if (!user || user.role !== 'staff') return <Navigate to="/" />;

  const handleChangePassword = (e) => {
    e.preventDefault();
    const currentUserData = staffList.find(s => s.id === user.id);

    if (currentUserData.password !== passForm.oldPass) {
      alert("Mật khẩu cũ không chính xác!");
      return;
    }
    if (passForm.newPass !== passForm.confirmPass) {
      alert("Mật khẩu xác nhận không khớp!");
      return;
    }
    if (passForm.newPass.length < 3) {
      alert("Mật khẩu mới quá ngắn!");
      return;
    }

    updatePassword(user.id, passForm.newPass);
    alert("Đổi mật khẩu thành công!");
    setShowModal(false);
    setPassForm({ oldPass: '', newPass: '', confirmPass: '' });
  };

  return (
    <div>
      {/* Header với Logo */}
      <header style={{ background: '#FF9900', color: 'white', padding: '10px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <img 
            src="/BA LOGO.png" 
            alt="Be Able VN Logo" 
            style={{ height: '50px', objectFit: 'contain', backgroundColor: 'white', borderRadius: '8px', padding: '2px' }} 
          />
          <h3 style={{ margin: 0 }}>Be Able VN - Nhân sự</h3>
        </div>
        
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <span 
            onClick={() => setShowModal(true)}
            style={{ fontWeight: 'bold', cursor: 'pointer', textDecoration: 'underline' }}
            title="Click để đổi mật khẩu"
          >
            {user.name} ⚙️
          </span>
          <button 
            onClick={logout}
            style={{ padding: '6px 15px', cursor: 'pointer', borderRadius: '4px', border: 'none', fontWeight: 'bold', color: '#FF9900', background: 'white' }}
          >
            Đăng xuất
          </button>
        </div>
      </header>

      <nav style={{ background: '#eee', padding: '15px 20px', borderBottom: '1px solid #ddd' }}>
        <Link to="/staff/attendance" style={{ marginRight: '25px', textDecoration: 'none', color: '#333', fontWeight: 'bold' }}>🕒 Điểm danh</Link>
        <Link to="/staff/my-tasks" style={{ marginRight: '25px', textDecoration: 'none', color: '#333', fontWeight: 'bold' }}>📝 Công việc của tôi</Link>
        <Link to="/staff/facility-check" style={{ textDecoration: 'none', color: '#333', fontWeight: 'bold' }}>🛠️ Kiểm tra CSVC</Link>
      </nav>
      
      <main style={{ padding: '20px', minHeight: '80vh', backgroundColor: '#fff', position: 'relative' }}>
        <Outlet />
      </main>

      {/* Modal Đổi mật khẩu */}
      {showModal && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000
        }}>
          <div style={{ background: 'white', padding: '25px', borderRadius: '10px', width: '350px', boxShadow: '0 5px 15px rgba(0,0,0,0.2)' }}>
            <h3 style={{ marginTop: 0, color: '#333' }}>Đổi mật khẩu</h3>
            <form onSubmit={handleChangePassword}>
              <div style={{ marginBottom: '15px' }}>
                <label style={{ display: 'block', marginBottom: '5px' }}>Mật khẩu cũ:</label>
                <input type="password" required style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
                  value={passForm.oldPass} onChange={e => setPassForm({...passForm, oldPass: e.target.value})} />
              </div>
              <div style={{ marginBottom: '15px' }}>
                <label style={{ display: 'block', marginBottom: '5px' }}>Mật khẩu mới:</label>
                <input type="password" required style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
                  value={passForm.newPass} onChange={e => setPassForm({...passForm, newPass: e.target.value})} />
              </div>
              <div style={{ marginBottom: '20px' }}>
                <label style={{ display: 'block', marginBottom: '5px' }}>Nhập lại mật khẩu mới:</label>
                <input type="password" required style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
                  value={passForm.confirmPass} onChange={e => setPassForm({...passForm, confirmPass: e.target.value})} />
              </div>
              <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '10px' }}>
                <button type="button" onClick={() => setShowModal(false)} style={{ padding: '8px 15px', background: '#ccc', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>Hủy</button>
                <button type="submit" style={{ padding: '8px 15px', background: '#FF9900', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }}>Lưu thay đổi</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default StaffLayout;
